# Extract team data from rows
def extract_page_id(url):
    """Extract page ID from Confluence URL."""
    if '/wiki/x/' in url:
        match = re.search(r'/wiki/x/([A-Za-z0-9_-]+)', url)
        return match.group(1) if match else None
    elif '/pages/' in url:
        match = re.search(r'/pages/(\d+)', url)
        return match.group(1) if match else None
    return None

def extract_board_id(url):
    """Extract board ID from Jira URL."""
    if not url:
        return None
    match = re.search(r'/boards/(\d+)', url)
    return match.group(1) if match else None

# Parse rows
teams = []
rows = html_content.split('</tr><tr>')

for row in rows:
    # Extract all td cells
    cells = row.split('</td>')

    if len(cells) < 5:
        continue

    # Cell 0: Team page link
    team_page_match = re.search(r'<a href="([^"]+)"', cells[0])
    team_page_link = team_page_match.group(1) if team_page_match else None

    # Cell 4: Sprint board link
    board_match = re.search(r'<a href="([^"]+)"', cells[4])
    sprint_board_link = board_match.group(1) if board_match else None

    if team_page_link:
        page_id = extract_page_id(team_page_link)
        board_id = extract_board_id(sprint_board_link)

        teams.append({
            "pageLink": team_page_link,
            "sprintBoardLink": sprint_board_link,
            "pageId": page_id,
            "boardId": board_id
        })

# Generate teams.json
output = {
    "metadata": {
        "scan_date": datetime.now().isoformat(),
        "scan_timestamp_cet": "20260529 12-26",
        "source_page": "https://adgear.atlassian.net/wiki/spaces/ENG/pages/19470090380/SRPOL+Teams",
        "team_count": len(teams),
        "cloudId": "adgear.atlassian.net",
        "scanner_version": "2.0"
    },
    "teams": []
}

with open('teams_preliminary.json', 'w', encoding='utf-8') as f:
    json.dump({"teams": teams}, f, indent=2)

with open('teams.json', 'w', encoding='utf-8') as f:
    json.dump(output, f, indent=2)

print(f"Found {len(teams)} teams")
for i, team in enumerate(teams, 1):
    print(f"{i}. Page ID: {team['pageId']}, Board ID: {team.get('boardId', 'none')}")
